```typescript
export type DeliveryState =
  | { status: "none" }
  | { status: "dispatched"; id: string; courier: string }
  | { status: "delivered"; id: string; courier: string; deliveredAt: string }
  | { status: "failed"; id: string; reason: string };

export type DeliveryCommand =
  | { type: "dispatch"; id: string; courier: string }
  | { type: "deliver"; at: string }
  | { type: "fail"; reason: string };

export type DeliveryEvent =
  | { type: "DeliveryDispatched"; id: string; courier: string }
  | { type: "DeliveryDelivered"; at: string }
  | { type: "DeliveryFailed"; reason: string };

export class DeliveryError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const deliveryDecider: Decider<DeliveryCommand, DeliveryEvent, DeliveryState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "dispatch":
        if (state.status !== "none") throw new DeliveryError("ALREADY_DISPATCHED");
        if (command.courier.length === 0) throw new DeliveryError("NO_COURIER");
        return [{ type: "DeliveryDispatched", id: command.id, courier: command.courier }];
      case "deliver":
        if (state.status === "failed") throw new DeliveryError("ALREADY_FAILED");
        if (state.status !== "dispatched") throw new DeliveryError("NOT_DISPATCHED");
        return [{ type: "DeliveryDelivered", at: command.at }];
      case "fail":
        if (state.status !== "dispatched") throw new DeliveryError("NOT_DISPATCHED");
        return [{ type: "DeliveryFailed", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new DeliveryError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DeliveryDispatched":
        return { status: "dispatched", id: event.id, courier: event.courier };
      case "DeliveryDelivered":
        if (state.status !== "dispatched") return state;
        return { status: "delivered", id: state.id, courier: state.courier, deliveredAt: event.at };
      case "DeliveryFailed":
        if (state.status !== "dispatched") return state;
        return { status: "failed", id: state.id, reason: event.reason };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
```

A Decider is pure: decide(command, state) returns events (or throws), and evolve(state, event) folds events into new state. Unlike CRUD, no state is mutated in place; history is the source of truth and can be replayed.

```typescript
export type InventoryState =
  | { status: "empty" }
  | { status: "stocked"; sku: string; onHand: number; reserved: number };

export type InventoryCommand =
  | { type: "receive"; sku: string; qty: number }
  | { type: "reserve"; qty: number }
  | { type: "release"; qty: number };

export type InventoryEvent =
  | { type: "StockReceived"; sku: string; qty: number }
  | { type: "StockReserved"; qty: number }
  | { type: "StockReleased"; qty: number };

export class InventoryError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const inventoryDecider: Decider<InventoryCommand, InventoryEvent, InventoryState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "receive":
        if (command.qty <= 0) throw new InventoryError("NON_POSITIVE");
        return [{ type: "StockReceived", sku: command.sku, qty: command.qty }];
      case "reserve": {
        if (state.status !== "stocked") throw new InventoryError("EMPTY");
        const available = state.onHand - state.reserved;
        if (command.qty > available) throw new InventoryError("INSUFFICIENT");
        return [{ type: "StockReserved", qty: command.qty }];
      }
      case "release": {
        if (state.status !== "stocked") throw new InventoryError("EMPTY");
        if (command.qty > state.reserved) throw new InventoryError("OVER_RELEASE");
        return [{ type: "StockReleased", qty: command.qty }];
      }
      default: {
        const _n: never = command;
        throw new InventoryError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "StockReceived":
        if (state.status === "empty") return { status: "stocked", sku: event.sku, onHand: event.qty, reserved: 0 };
        return { ...state, onHand: state.onHand + event.qty };
      case "StockReserved":
        if (state.status !== "stocked") return state;
        return { ...state, reserved: state.reserved + event.qty };
      case "StockReleased":
        if (state.status !== "stocked") return state;
        return { ...state, reserved: state.reserved - event.qty };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
