```typescript
export type TenantState =
  | { status: "none" }
  | { status: "active"; id: string; name: string }
  | { status: "suspended"; id: string; name: string; reason: string };

export type TenantCommand =
  | { type: "onboard"; id: string; name: string }
  | { type: "suspend"; reason: string }
  | { type: "reactivate" };

export type TenantEvent =
  | { type: "TenantOnboarded"; id: string; name: string }
  | { type: "TenantSuspended"; reason: string }
  | { type: "TenantReactivated" };

export class TenantError extends Error {
  constructor(public readonly code: string) {
    super(code);
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const tenantDecider: Decider<TenantCommand, TenantEvent, TenantState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "onboard":
        if (state.status !== "none") throw new TenantError("EXISTS");
        if (command.name.length === 0) throw new TenantError("INVALID_NAME");
        return [{ type: "TenantOnboarded", id: command.id, name: command.name }];
      case "suspend":
        if (state.status !== "active") throw new TenantError("NOT_ACTIVE");
        return [{ type: "TenantSuspended", reason: command.reason }];
      case "reactivate":
        if (state.status !== "suspended") throw new TenantError("NOT_SUSPENDED");
        return [{ type: "TenantReactivated" }];
      default: {
        const _n: never = command;
        throw new TenantError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "TenantOnboarded":
        return { status: "active", id: event.id, name: event.name };
      case "TenantSuspended":
        if (state.status !== "active") return state;
        return { status: "suspended", id: state.id, name: state.name, reason: event.reason };
      case "TenantReactivated":
        if (state.status !== "suspended") return state;
        return { status: "active", id: state.id, name: state.name };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
