```typescript
export type BookingState =
  | { status: "none" }
  | { status: "requested"; id: string; guests: number }
  | { status: "confirmed"; id: string; guests: number; at: string }
  | { status: "cancelled"; id: string; reason: string };

export type BookingCommand =
  | { type: "request"; id: string; guests: number }
  | { type: "confirm"; at: string }
  | { type: "cancel"; reason: string };

export type BookingEvent =
  | { type: "BookingRequested"; id: string; guests: number }
  | { type: "BookingConfirmed"; at: string }
  | { type: "BookingCancelled"; reason: string };

export class BookingError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const bookingDecider: Decider<BookingCommand, BookingEvent, BookingState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "request":
        if (state.status !== "none") throw new BookingError("EXISTS");
        if (command.guests <= 0) throw new BookingError("NO_GUESTS");
        return [{ type: "BookingRequested", id: command.id, guests: command.guests }];
      case "confirm":
        if (state.status !== "requested") throw new BookingError("NOT_REQUESTED");
        return [{ type: "BookingConfirmed", at: command.at }];
      case "cancel":
        if (state.status === "cancelled") throw new BookingError("ALREADY_CANCELLED");
        if (state.status === "none") throw new BookingError("NONE");
        return [{ type: "BookingCancelled", reason: command.reason }];
      default: {
        const _n: never = command;
        throw new BookingError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "BookingRequested":
        return { status: "requested", id: event.id, guests: event.guests };
      case "BookingConfirmed":
        if (state.status !== "requested") return state;
        return { status: "confirmed", id: state.id, guests: state.guests, at: event.at };
      case "BookingCancelled":
        if (state.status === "none" || state.status === "cancelled") return state;
        return { status: "cancelled", id: state.id, reason: event.reason };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
