```typescript
export type OrderEvent =
  | { type: "OrderPlaced"; data: { id: string; customerId: string; total: number } }
  | { type: "OrderPaid"; data: { at: string } }
  | { type: "OrderShipped"; data: { tracking: string } }
  | { type: "OrderCancelled"; data: { reason: string } };

export type OrderView = Readonly<{
  id: string;
  customerId: string;
  total: number;
  status: "placed" | "paid" | "shipped" | "cancelled";
  paidAt?: string;
  tracking?: string;
  cancelReason?: string;
}>;

export function when(
  current: Partial<OrderView>,
  event: OrderEvent,
): Partial<OrderView> {
  switch (event.type) {
    case "OrderPlaced":
      return {
        id: event.data.id,
        customerId: event.data.customerId,
        total: event.data.total,
        status: "placed",
      };
    case "OrderPaid":
      return { ...current, status: "paid", paidAt: event.data.at };
    case "OrderShipped":
      return { ...current, status: "shipped", tracking: event.data.tracking };
    case "OrderCancelled":
      return { ...current, status: "cancelled", cancelReason: event.data.reason };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function aggregateStream<V, E>(
  events: E[],
  reducer: (v: Partial<V>, e: E) => Partial<V>,
  check: (v: Partial<V>) => v is V,
): V {
  const state = events.reduce<Partial<V>>(reducer, {});
  if (!check(state)) throw new Error("VIEW_INCOMPLETE");
  return state;
}

export function isOrderView(v: Partial<OrderView>): v is OrderView {
  return typeof v.id === "string" && typeof v.customerId === "string" && typeof v.total === "number" && typeof v.status === "string";
}

export function orderViewFrom(events: OrderEvent[]): OrderView {
  return aggregateStream<OrderView, OrderEvent>(events, when, isOrderView);
}
