```typescript
export type InventoryEvent =
  | { type: "StockReceived"; sku: string; qty: number }
  | { type: "StockReserved"; sku: string; qty: number }
  | { type: "StockReleased"; sku: string; qty: number }
  | { type: "StockCounted"; sku: string; countedAt: string };

export type LowStockView = Readonly<{
  bySku: Readonly<Record<string, number>>;
  threshold: number;
  lowCount: number;
}>;

export const emptyView: LowStockView = { bySku: {}, threshold: 10, lowCount: 0 };

function adjust(view: LowStockView, sku: string, delta: number): LowStockView {
  const current = view.bySku[sku] ?? 0;
  const next = current + delta;
  const nextBySku: Record<string, number> = { ...view.bySku, [sku]: next };
  const lowCount = Object.values(nextBySku).filter((v) => v < view.threshold).length;
  return { bySku: nextBySku, threshold: view.threshold, lowCount };
}

export function project(view: LowStockView, event: InventoryEvent): LowStockView {
  switch (event.type) {
    case "StockReceived":
      return adjust(view, event.sku, event.qty);
    case "StockReserved":
      return adjust(view, event.sku, -event.qty);
    case "StockReleased":
      return adjust(view, event.sku, event.qty);
    case "StockCounted":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function buildView(events: InventoryEvent[]): LowStockView {
  return events.reduce(project, emptyView);
}
