```typescript
export type ManifestEvent =
  | { type: "ManifestOpened"; data: { id: string; carrier: string } }
  | { type: "ParcelAdded"; data: { parcelId: string; weight: number } }
  | { type: "ParcelRemoved"; data: { parcelId: string } }
  | { type: "ManifestSealed"; data: { sealedAt: string } };

export type CarrierCountsView = Readonly<{
  byCarrier: Readonly<Record<string, number>>;
  activeManifest?: { id: string; carrier: string; parcels: number };
}>;

export const emptyCarrierCounts: CarrierCountsView = { byCarrier: {} };

export function project(view: CarrierCountsView, event: ManifestEvent): CarrierCountsView {
  switch (event.type) {
    case "ManifestOpened":
      return {
        ...view,
        activeManifest: { id: event.data.id, carrier: event.data.carrier, parcels: 0 },
      };
    case "ParcelAdded": {
      const m = view.activeManifest;
      if (!m) return view;
      return { ...view, activeManifest: { ...m, parcels: m.parcels + 1 } };
    }
    case "ParcelRemoved": {
      const m = view.activeManifest;
      if (!m) return view;
      return { ...view, activeManifest: { ...m, parcels: Math.max(0, m.parcels - 1) } };
    }
    case "ManifestSealed": {
      const m = view.activeManifest;
      if (!m) return view;
      const prev = view.byCarrier[m.carrier] ?? 0;
      const byCarrier: Record<string, number> = { ...view.byCarrier, [m.carrier]: prev + m.parcels };
      return { byCarrier };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function build(events: ManifestEvent[]): CarrierCountsView {
  return events.reduce(project, emptyCarrierCounts);
}
