```typescript
export type BookingEvent =
  | { type: "BookingRequested"; bookingId: string }
  | { type: "BookingConfirmed"; bookingId: string; at: string }
  | { type: "BookingCancelled"; bookingId: string; reason: string }
  | { type: "BookingArchived"; bookingId: string };

export type BookingDashboard = Readonly<{
  pending: number;
  confirmed: number;
  cancelled: number;
  archived: number;
  lastUpdatedAt?: string;
}>;

export const emptyDashboard: BookingDashboard = {
  pending: 0,
  confirmed: 0,
  cancelled: 0,
  archived: 0,
};

export function project(view: BookingDashboard, event: BookingEvent): BookingDashboard {
  switch (event.type) {
    case "BookingRequested":
      return { ...view, pending: view.pending + 1 };
    case "BookingConfirmed":
      return {
        ...view,
        pending: Math.max(0, view.pending - 1),
        confirmed: view.confirmed + 1,
        lastUpdatedAt: event.at,
      };
    case "BookingCancelled":
      return {
        ...view,
        pending: Math.max(0, view.pending - 1),
        cancelled: view.cancelled + 1,
      };
    case "BookingArchived":
      return { ...view, archived: view.archived + 1 };
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function buildDashboard(events: BookingEvent[]): BookingDashboard {
  return events.reduce(project, emptyDashboard);
}
