```typescript
export type Snapshot<S> = { version: number; state: S };

export type DeliveryV1 = { id: string; courier: string };
export type DeliveryV2 = { id: string; courier: string; status: "dispatched" | "delivered" };
export type DeliveryV3 = {
  id: string;
  courier: string;
  status: "dispatched" | "delivered" | "failed";
  attempts: number;
};

export type CurrentDelivery = DeliveryV3;
export const CURRENT_VERSION = 3;

export class SnapshotUpgradeError extends Error {}

function v1Tov2(s: DeliveryV1): DeliveryV2 {
  return { ...s, status: "dispatched" };
}

function v2Tov3(s: DeliveryV2): DeliveryV3 {
  return { ...s, attempts: 1 };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDelivery> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version < 1 || version > CURRENT_VERSION) {
    throw new SnapshotUpgradeError(`UNSUPPORTED_${version}`);
  }
  if (version === 1) {
    state = v1Tov2(state as DeliveryV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as DeliveryV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new SnapshotUpgradeError("INCOMPLETE");
  const upgraded = state as CurrentDelivery;
  if (typeof upgraded.id !== "string" || typeof upgraded.attempts !== "number") {
    throw new SnapshotUpgradeError("SHAPE_MISMATCH");
  }
  return { version, state: upgraded };
}

export function loadDelivery(raw: Snapshot<unknown>): CurrentDelivery {
  return upgradeSnapshot(raw).state;
}
