```typescript
export type Snapshot<S> = { version: number; state: S };

export type TenantV1 = { id: string; name: string };
export type TenantV2 = {
  id: string;
  name: string;
  plan: "free" | "pro" | "enterprise";
  seats: number;
};

export type CurrentTenant = TenantV2;
export const CURRENT_VERSION = 2;

export class SnapshotUpgradeError extends Error {
  constructor(public readonly code: string) {
    super(code);
  }
}

function v1Tov2(s: TenantV1): TenantV2 {
  return { ...s, plan: "free", seats: 1 };
}

function assertCurrent(value: unknown): asserts value is CurrentTenant {
  if (typeof value !== "object" || value === null) {
    throw new SnapshotUpgradeError("NOT_OBJECT");
  }
  const v = value as Partial<CurrentTenant>;
  if (typeof v.id !== "string" || typeof v.name !== "string" || typeof v.seats !== "number") {
    throw new SnapshotUpgradeError("SHAPE_MISMATCH");
  }
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentTenant> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version < 1 || version > CURRENT_VERSION) {
    throw new SnapshotUpgradeError(`UNSUPPORTED_${version}`);
  }
  if (version === 1) {
    state = v1Tov2(state as TenantV1);
    version = 2;
  }
  assertCurrent(state);
  return { version, state };
}
