import { Effect } from "effect";

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: E[]; revision: bigint | null }>;
  appendToStream(
    stream: string,
    events: E[],
    options: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export function commandHandlerFor<C, E, S>(
  decider: Decider<C, E, S>,
  eventStore: EventStore<E>,
) {
  return async function handle(streamName: string, command: C): Promise<bigint | null> {
    const { events, revision } = await eventStore.readStream(streamName);
    const state = events.reduce(decider.evolve, decider.initialState);
    const newEvents = decider.decide(command, state);
    if (newEvents.length === 0) return revision;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return eventStore.appendToStream(streamName, newEvents, { expectedRevision });
  };
}

export const commandHandlerEffect = <C, E, S>(
  decider: Decider<C, E, S>,
  eventStore: EventStore<E>,
) => (streamName: string, command: C) =>
  Effect.gen(function* () {
    const { events, revision } = yield* Effect.promise(() => eventStore.readStream(streamName));
    const state = events.reduce(decider.evolve, decider.initialState);
    const newEvents = decider.decide(command, state);
    if (newEvents.length === 0) return revision;
    const expectedRevision: ExpectedRevision = revision ?? "no_stream";
    return yield* Effect.promise(() =>
      eventStore.appendToStream(streamName, newEvents, { expectedRevision }),
    );
  });
