export type InventoryEvent =
  | { type: "StockReceived"; sku: string; qty: number }
  | { type: "StockReserved"; sku: string; qty: number }
  | { type: "StockReleased"; sku: string; qty: number };

export type InventoryView = Readonly<{
  onHand: Readonly<Record<string, number>>;
}>;

export const emptyView: InventoryView = { onHand: {} };

export function project(view: InventoryView, event: InventoryEvent): InventoryView {
  switch (event.type) {
    case "StockReceived": {
      const prev = view.onHand[event.sku] ?? 0;
      return { onHand: { ...view.onHand, [event.sku]: prev + event.qty } };
    }
    case "StockReserved": {
      const prev = view.onHand[event.sku] ?? 0;
      return { onHand: { ...view.onHand, [event.sku]: prev - event.qty } };
    }
    case "StockReleased": {
      const prev = view.onHand[event.sku] ?? 0;
      return { onHand: { ...view.onHand, [event.sku]: prev + event.qty } };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export interface EventReader<E> {
  readBatch(from: bigint, size: number): Promise<{ events: ReadonlyArray<{ position: bigint; event: E }>; done: boolean }>;
}

export interface Persistence<V> {
  wipe(): Promise<void>;
  save(view: V, cursor: bigint): Promise<void>;
}

export interface RebuildOptions<V, E> {
  from: bigint;
  batchSize: number;
  project: (view: V, event: E) => V;
  persist: Persistence<V>;
  reader: EventReader<E>;
  empty: V;
  onProgress?: (cursor: bigint) => void;
}

export async function rebuild<V, E>(opts: RebuildOptions<V, E>): Promise<bigint> {
  if (opts.from === 0n) await opts.persist.wipe();
  let view: V = opts.empty;
  let cursor: bigint = opts.from;
  while (true) {
    const batch = await opts.reader.readBatch(cursor, opts.batchSize);
    if (batch.events.length === 0) return cursor;
    for (const { position, event } of batch.events) {
      view = opts.project(view, event);
      cursor = position + 1n;
    }
    await opts.persist.save(view, cursor);
    opts.onProgress?.(cursor);
    if (batch.done) return cursor;
  }
}
