export type DeliveryEvent =
  | { type: "DeliveryDispatched"; id: string; courier: string }
  | { type: "DeliveryDelivered"; at: string }
  | { type: "DeliveryFailed"; reason: string };

export type DeliveryState =
  | { status: "none" }
  | { status: "dispatched"; id: string; courier: string }
  | { status: "delivered"; id: string; at: string }
  | { status: "failed"; id: string; reason: string };

export type DeliveryCommand =
  | { type: "dispatch"; id: string; courier: string }
  | { type: "markDelivered"; at: string }
  | { type: "markFailed"; reason: string };

export class DeliveryError extends Error {}

export function evolve(state: DeliveryState, event: DeliveryEvent): DeliveryState {
  switch (event.type) {
    case "DeliveryDispatched":
      return { status: "dispatched", id: event.id, courier: event.courier };
    case "DeliveryDelivered":
      if (state.status !== "dispatched") return state;
      return { status: "delivered", id: state.id, at: event.at };
    case "DeliveryFailed":
      if (state.status !== "dispatched") return state;
      return { status: "failed", id: state.id, reason: event.reason };
    default: {
      const _n: never = event;
      return state;
    }
  }
}

export function decide(command: DeliveryCommand, state: DeliveryState): DeliveryEvent[] {
  switch (command.type) {
    case "dispatch":
      if (state.status !== "none") throw new DeliveryError("EXISTS");
      return [{ type: "DeliveryDispatched", id: command.id, courier: command.courier }];
    case "markDelivered":
      if (state.status !== "dispatched") throw new DeliveryError("NOT_DISPATCHED");
      return [{ type: "DeliveryDelivered", at: command.at }];
    case "markFailed":
      if (state.status !== "dispatched") throw new DeliveryError("NOT_DISPATCHED");
      return [{ type: "DeliveryFailed", reason: command.reason }];
    default: {
      const _n: never = command;
      throw new DeliveryError("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: DeliveryEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: DeliveryEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export async function handle(store: EventStore, stream: string, cmd: DeliveryCommand): Promise<bigint | null> {
  const { events, revision } = await store.readStream(stream);
  const state = events.reduce(evolve, { status: "none" } as DeliveryState);
  const newEvents = decide(cmd, state);
  if (newEvents.length === 0) return revision;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  return store.appendToStream(stream, newEvents, { expectedRevision });
}
